from typing import List

# 滑动窗口模板：解决「最小覆盖子串」「最长无重复子串」等问题
def sliding_window_template(s: str, t: str) -> str:
    need = {}  # 记录目标字符及其所需次数
    window = {}  # 记录当前窗口中各字符出现次数

    for c in t:
        need[c] = need.get(c, 0) + 1

    left, right = 0, 0
    valid = 0  # 窗口中满足 need 条件的字符个数

    while right < len(s):
        c = s[right]
        right += 1
        # 扩大窗口：更新窗口数据
        if c in need:
            window[c] = window.get(c, 0) + 1
            if window[c] == need[c]:
                valid += 1

        # 收缩窗口：判断左侧是否需要收缩
        while 需要收缩的条件:  # 如窗口已覆盖所有 need 字符
            # 更新最优结果
            if valid == len(need):
                # 记录答案
                pass

            d = s[left]
            left += 1
            # 缩小窗口：更新窗口数据
            if d in need:
                if window[d] == need[d]:
                    valid -= 1
                window[d] -= 1

    return 最优结果

# 二分查找模板：查找左边界（第一个等于 target 的位置）
def binary_search_left(nums: List[int], target: int) -> int:
    left, right = 0, len(nums) - 1

    while left <= right:
        mid = left + (right - left) // 2
        if nums[mid] < target:
            left = mid + 1
        elif nums[mid] > target:
            right = mid - 1
        else:
            right = mid - 1  # 锁定左侧边界

    # 检查越界及是否找到
    if left >= len(nums) or nums[left] != target:
        return -1
    return left
